#include<bits/stdc++.h>
using namespace std;
int p[110],c[110];
long double dp[110];
int a[110][110],n,m;
vector<int> v[110];
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        scanf("%d%d",&c[i],&p[i]);
        for(int j=1;j<=p[i];j++)
        {
            scanf("%d",&a[i][j]);
            v[a[i][j]].push_back(i);
        }
    }
    for(int i=1;i<=m;i++)
    {
        dp[i]=1e18;
        for(int j=1;j<=n;j++)
        {
            int cnt=0;
            long double sum=0;
            for(int k=1;k<=p[j];k++)
            {
                if(a[j][k]==0)
                {
                    cnt++;
                    continue;
                }
                sum+=dp[max(0,i-a[j][k])];
            }
            sum+=c[j]*p[j];
            sum/=(p[j]-cnt);
            dp[i]=min(dp[i],sum);
        }
    }
    cout<<fixed<<setprecision(15)<<dp[m];
    return 0;
}
